// Solution
#include <iostream>

class Solution {
public:
bool bubbleSort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        bool swapped = false;
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
                swapped = true;
            }
        }
        if (!swapped) break;
    }
    return true;
}
};

int main() {
    int n;
    std::cin >> n;
    int arr[n];
    for (int i = 0; i < n; i++) {
        std::cin >> arr[i];
    }
    Solution solution;
    solution.bubbleSort(arr, n);
    for (int i = 0; i < n; i++) {
        std::cout << arr[i] << ' ';
    }
    return 0;
}

